static const char *TAG = "ECG_SSM_INFERENCE";

/**
 * Welford's Algorithm implementation
 * Computes online mean and variance for real-time Z-score normalization.
 */
class Welford {
private:
    int count;
    float mean;
    float M2;

public:
    Welford() : count(0), mean(0.0f), M2(0.0f) {}

    // Update running statistics with a new sample
    void update(float newValue) {
        count++;
        float delta = newValue - mean;
        mean += delta / count;
        float delta2 = newValue - mean;
        M2 += delta * delta2;
    }

    float getMean() const { return mean; }
    
    // Calculates population variance
    float getVariance() const {
        if (count < 2) return 1.0f; // Prevent division by zero initially
        return M2 / count; 
    }

    // Returns the Z-score normalized value
    float normalize(float value) const {
        if (count < 2) return 0.0f;
        float stddev = sqrtf(getVariance());
        // Epsilon to avoid division by zero
        return (value - mean) / (stddev + 1e-7f);
    }
};

